import React from 'react';

const ScreenThree = ({ healthConditions, handleConditionChange, handleOtherConditionDetailsChange }) => {
  const conditions = [
    'No, I am not experiencing any health problems',
    'Cardiovascular disease (e.g., Hypertension, Coronary Artery Disease)',
    'Diabetes (Type 1 or Type 2)',
    'Chronic Respiratory Condition (e.g., Asthma, COPD)',
    'Chronic Digestive Issue (e.g., IBS, Crohn\'s Disease, Celiac Disease)',
    'Chronic Autoimmune Condition (e.g., Rheumatoid Arthritis, Lupus)',
    'Hormonal Disorder (e.g., Thyroid Disease, PCOS)',
    'Chronic Skin Condition (e.g., Psoriasis, Eczema)',
    'Other Conditions'
  ];

  const handleCheckboxChange = (event) => {
    const { value } = event.target;
    handleConditionChange(value);
  };

  const handleTextareaChange = (event) => {
    handleOtherConditionDetailsChange(event.target.value);
  };

  return (
    <div>
      <h2>Are you currently experiencing any health problems or have any chronic diseases?</h2>
      <div className="form-group">
        {conditions.map((condition, index) => (
          <div key={index} className="checkbox-group">
            <label>
              <input
                type="checkbox"
                value={condition}
                checked={healthConditions.selectedConditions.includes(condition)}
                onChange={handleCheckboxChange}
              />
              {condition}
            </label>
          </div>
        ))}
        {healthConditions.selectedConditions.includes('Other Conditions') && (
          <div className="form-group">
            <label htmlFor="otherConditionDetails">Please specify:</label>
            <textarea
              id="otherConditionDetails"
              name="otherConditionDetails"
              value={healthConditions.otherConditionDetails}
              onChange={handleTextareaChange}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default ScreenThree;
